Here is a complete, single-file HTML solution using **Three.js**. This code generates a 3D house procedurally (using code to build the geometry) so you don't need to download any external 3D model files.

You can save the code below as an `.html` file (e.g., `house.html`) and open it in any modern web browser.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>3D House Render</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click & Drag to Rotate | Scroll to Zoom</div>

    <!-- Import Three.js from CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 15);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true; // Enable shadows
        document.body.appendChild(renderer.domElement);

        // 2. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.target.set(0, 2, 0);

        // 3. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1.5);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0xE0E0E0 }); // White walls
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown roof
        const glassMaterial = new THREE.MeshStandardMaterial({ color: 0xADD8E6, transparent: true, opacity: 0.6 });
        const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x5C4033 });
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0x88ccff });
        const grassMaterial = new THREE.MeshStandardMaterial({ color: 0x4caf50 });

        // 5. Building the House
        const houseGroup = new THREE.Group();

        // --- Floor ---
        const floorGeo = new THREE.BoxGeometry(10, 1, 10);
        const floor = new THREE.Mesh(floorGeo, grassMaterial);
        floor.position.y = -0.5;
        floor.receiveShadow = true;
        houseGroup.add(floor);

        // --- Main Body ---
        const bodyGeo = new THREE.BoxGeometry(8, 4, 6);
        const body = new THREE.Mesh(bodyGeo, wallMaterial);
        body.position.y = 2;
        body.castShadow = true;
        body.receiveShadow = true;
        houseGroup.add(body);

        // --- Roof ---
        const roofGeo = new THREE.ConeGeometry(6, 3, 4);
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = 5.5;
        roof.rotation.y = Math.PI / 4; // Rotate to align with house
        roof.castShadow = true;
        houseGroup.add(roof);

        // --- Windows ---
        function createWindow(x, z, y, w, d) {
            const winGeo = new THREE.BoxGeometry(w, 1.5, d);
            const win = new THREE.Mesh(winGeo, windowMaterial);
            win.position.set(x, y, z);
            win.castShadow = true;
            houseGroup.add(win);
        }

        createWindow(2.5, 2.5, 2.5, 1.5, 1.5); // Front Right
        createWindow(-2.5, 2.5, 2.5, 1.5, 1.5); // Front Left
        createWindow(2.5, -2.5, 2.5, 1.5, 1.5); // Back Right
        createWindow(-2.5, -2.5, 2.5, 1.5, 1.5); // Back Left

        // --- Door ---
        const doorGeo = new THREE.BoxGeometry(1.5, 2.5, 0.2);
        const door = new THREE.Mesh(doorGeo, doorMaterial);
        door.position.set(0, 1.25, 3.1); // Slightly pushed out
        door.castShadow = true;
        houseGroup.add(door);

        // --- Chimney ---
        const chimneyGeo = new THREE.BoxGeometry(1, 2, 1);
        const chimney = new THREE.Mesh(chimneyGeo, wallMaterial);
        chimney.position.set(3, 6.5, 0);
        chimney.castShadow = true;
        houseGroup.add(chimney);

        scene.add(houseGroup);

        // 6. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Window Resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### How to use this:
1.  Copy the code block above.
2.  Create a new file on your computer named `house.html`.
3.  Paste the code into that file and save it.
4.  Double-click `house.html` to open it in your browser.

### Features included:
*   **Procedural Generation:** The house is built using geometric primitives (Boxes, Cones) rather than loading an external file.
*   **Lighting & Shadows:** Includes a directional light that casts realistic shadows on the ground and the house itself.
*   **Interactivity:** You can click and drag to rotate around the house, and scroll to zoom in/out.
*   **Materials:** Includes distinct materials for grass, walls, roof, windows, and the door.
